/**
 * Ding-dong chime encoded as base64 (built-in fallback).
 *
 * This is the REAL MP3 ding-dong sound from BusGo (notification-company.mp3).
 * Source: upload/otification-company.mp3 (65 KB MP3, 128 kbps, 44.1 kHz, stereo)
 * Encoded size: ~87 KB base64 (inlined in the JS bundle)
 *
 * Priority chain in playDingDong():
 *   1. Agency-uploaded MP3 (customDingDongUrl) - highest priority
 *   2. This hardcoded base64 chime - realistic default (THIS FILE)
 *   3. Synthesized oscillator (880Hz/660Hz) - last-resort fallback
 *
 * The base64 is exposed both as raw (for AudioContext.decodeAudioData via
 * fetch+arrayBuffer) and as a data URI (for direct Audio.src assignment).
 */

// Placeholder replaced with actual base64 string below.
const RAW = "";

/**
 * Raw base64 string of the ding-dong MP3 (no data URI prefix).
 * Use with fetch() + arrayBuffer() + AudioContext.decodeAudioData().
 */
export const DING_DONG_BASE64_RAW: string = RAW;

/**
 * Ding-dong as a data URI (data:audio/mpeg;base64,...).
 * Use directly as `new Audio(src).src` for simple playback.
 */
export const DING_DONG_DATA_URI: string = "data:audio/mpeg;base64," + RAW;

/**
 * Whether the hardcoded ding-dong base64 is available.
 * Always true (constant) - exposed for explicit checks.
 */
export const HAS_HARDCODED_DING_DONG: boolean = true;
